# ── Litestream backup config (multi-tenant SQLite -> S3) ──────────────────────
# Flow stores one SQLite DB per team (/data/tenants/{team}/roadmap.db) and teams are
# created at runtime, but Litestream needs every DB enumerated in its config. These
# helpers generate a FLOW-OWNED Litestream config from the tenants directory so it is
# independent of any other Litestream setup on the box (e.g. sharebox is never touched -
# run Flow as its own `litestream-flow` service). Regenerated on `--new-team` and via
# `--sync-litestream`. Fully env-gated + best-effort: a no-op unless LITESTREAM_FLOW_CONFIG
# is set, so dev/local and the test suite are unaffected. Replicas authenticate via the
# EC2 instance role (no keys in the file) - same pattern as SES.
def _read_env_file(path):
    """Populate os.environ (setdefault, so real env wins) from a KEY=VALUE .env file."""
    try:
        if not os.path.exists(path):
            return
        with open(path) as f:
            for line in f:
                line = line.strip()
                if line and not line.startswith("#") and "=" in line:
                    k, v = line.split("=", 1)
                    os.environ.setdefault(k.strip(), v.strip())
    except Exception:
        pass

def _litestream_flow_yaml(tenants_dir, bucket, prefix, region):
    """Build the Litestream YAML enumerating every team's roadmap.db under tenants_dir.
    Returns (yaml_text, db_count)."""
    import glob
    dbs = sorted(glob.glob(os.path.join(tenants_dir, "*", "roadmap.db")))
    lines = [
        "# AUTO-GENERATED by Frazil Flow (server.py). Do NOT edit by hand - it is",
        "# regenerated by `python server.py --new-team <t>` and `--sync-litestream`.",
        "# One entry per team DB; replicas authenticate via the EC2 instance role.",
        "dbs:",
    ]
    for path in dbs:
        team = os.path.basename(os.path.dirname(path))
        lines += [
            "  - path: " + path,
            "    replicas:",
            "      - type: s3",
            "        bucket: " + bucket,
            "        path: " + prefix.rstrip("/") + "/" + team,
            "        region: " + region,
        ]
    return "\n".join(lines) + "\n", len(dbs)

def sync_litestream_config(tenants_dir=None, do_reload=True, verbose=False):
    """Regenerate the Flow Litestream config from disk and (best-effort) restart the
    litestream service so it picks up new team DBs. No-op unless LITESTREAM_FLOW_CONFIG
    is set. Never raises - a backup-config problem must never break team creation."""
    cfg_path = os.environ.get("LITESTREAM_FLOW_CONFIG", "").strip()
    if not cfg_path:
        if verbose:
            print("LITESTREAM_FLOW_CONFIG is not set - skipping Litestream sync (nothing to do).")
        return False
    bucket = os.environ.get("LITESTREAM_S3_BUCKET", "").strip()
    if not bucket:
        log.warning("[Litestream] LITESTREAM_FLOW_CONFIG set but LITESTREAM_S3_BUCKET missing - skipping.")
        if verbose:
            print("LITESTREAM_S3_BUCKET is not set - cannot build replicas. Skipping.")
        return False
    prefix = (os.environ.get("LITESTREAM_S3_PREFIX", "flow").strip() or "flow")
    region = (os.environ.get("AWS_REGION", "us-west-2").strip() or "us-west-2")
    tdir = tenants_dir or os.environ.get("FRAZIL_TENANTS_DIR", "/data/tenants")
    try:
        yaml_text, n = _litestream_flow_yaml(tdir, bucket, prefix, region)
        tmp = cfg_path + ".tmp"
        with open(tmp, "w") as f:
            f.write(yaml_text)
        os.replace(tmp, cfg_path)   # atomic swap
        log.info(f"[Litestream] wrote {cfg_path} ({n} team DB(s))")
        if verbose:
            print(f"Wrote {cfg_path} ({n} team DB(s) enumerated).")
    except Exception as e:
        log.warning(f"[Litestream] config write failed ({cfg_path}): {e}")
        if verbose:
            print(f"Litestream config write FAILED ({cfg_path}): {e}")
        return False
    if do_reload:
        cmd = os.environ.get("LITESTREAM_RELOAD_CMD", "systemctl restart litestream-flow").strip()
        if cmd:
            try:
                import subprocess
                subprocess.run(cmd, shell=True, check=True, timeout=30)
                log.info(f"[Litestream] reloaded via: {cmd}")
                if verbose:
                    print(f"Reloaded Litestream via: {cmd}")
            except Exception as e:
                log.warning(f"[Litestream] reload failed ({cmd}): {e} - reload manually to apply.")
                if verbose:
                    print(f"Reload FAILED ({cmd}): {e}\n  Config was written; run the reload manually to apply.")
    return True

# ── Handle --sync-litestream CLI (regenerate the Flow Litestream backup config) ──
# One-time initial enumeration of existing teams, and a re-runnable "make it match
# disk" command. Loads .env first so LITESTREAM_* can live there.
if "--sync-litestream" in sys.argv:
    _read_env_file(os.path.join(os.path.dirname(os.path.abspath(__file__)), ".env"))
    _ok = sync_litestream_config(verbose=True)
    sys.exit(0 if _ok else 1)

# ── Handle --new-team CLI ─────────────────────────────────────────────────────
if "--new-team" in sys.argv:
    idx = sys.argv.index("--new-team")
    if idx + 1 >= len(sys.argv):
        print("Usage: python server.py --new-team <teamname>")
        sys.exit(1)
    raw = sys.argv[idx + 1]
    slug = re.sub(r"[^a-z0-9]", "", raw.lower())
    if not slug:
        print(f"Invalid team name: {raw}")
        sys.exit(1)
    team_dir = os.path.join("/data/tenants", slug)
    if os.path.exists(team_dir):
        print(f"Team '{slug}' already exists at {team_dir}")
        sys.exit(0)
    os.makedirs(team_dir, exist_ok=True)
    _init_pw = secrets.token_urlsafe(12)
    print(f"Team '{slug}' created at {team_dir}")
    print(f"Initial login: admin / {_init_pw}")
    print(f"  (password change will be required on first login)")
    print(f"Link: https://roadmap.yourdomain.com?team={slug}")
    # Write the initial password into a temp file so init_team_db can pick it up
    _pw_file = os.path.join(team_dir, ".init_password")
    with open(_pw_file, "w") as _f:
        _f.write(_init_pw)
    # Keep the Litestream backup config in sync so the NEW team's DB starts replicating
    # immediately (no-op unless LITESTREAM_FLOW_CONFIG is configured on this host).
    _read_env_file(os.path.join(os.path.dirname(os.path.abspath(__file__)), ".env"))
    try:
        if sync_litestream_config(tenants_dir=os.path.dirname(team_dir), verbose=True):
            print("Litestream backup now covers this team.")
    except Exception as _e:
        print(f"(Litestream sync skipped: {_e})")
    sys.exit(0)

