def init_team_db(team: str):
    if team in _initialized_teams:
        return
    with db(team) as c:
        c.executescript("""
        CREATE TABLE IF NOT EXISTS projects (
            id   INTEGER PRIMARY KEY AUTOINCREMENT,
            data TEXT NOT NULL DEFAULT '{}'
        );
        CREATE TABLE IF NOT EXISTS config (
            key   TEXT PRIMARY KEY,
            value TEXT NOT NULL DEFAULT '[]'
        );
        CREATE TABLE IF NOT EXISTS audit_log (
            id           INTEGER PRIMARY KEY AUTOINCREMENT,
            ts           TEXT NOT NULL,
            username     TEXT NOT NULL DEFAULT '',
            action       TEXT NOT NULL,
            project_id   INTEGER,
            project_name TEXT,
            changes      TEXT
        );
        CREATE TABLE IF NOT EXISTS activities (
            id                  INTEGER PRIMARY KEY AUTOINCREMENT,
            activity_type       TEXT NOT NULL,
            source              TEXT NOT NULL DEFAULT 'System',
            item_id             INTEGER,
            item_name           TEXT,
            owner               TEXT,
            project             TEXT,
            created_by          TEXT,
            created_ts          TEXT,
            read_by             TEXT,
            read_ts             TEXT,
            resolved_by         TEXT,
            resolved_ts         TEXT,
            action_taken        TEXT,
            previous_value      TEXT,
            new_value           TEXT,
            note                TEXT,
            status              TEXT NOT NULL DEFAULT 'Open',
            message             TEXT
        );
        CREATE TABLE IF NOT EXISTS comments (
            id          INTEGER PRIMARY KEY AUTOINCREMENT,
            item_id     INTEGER NOT NULL,
            author      TEXT NOT NULL,
            body        TEXT NOT NULL,
            created_ts  TEXT NOT NULL,
            edited_ts   TEXT
        );
        CREATE TABLE IF NOT EXISTS key_counters (
            prefix          TEXT PRIMARY KEY,
            seq             INTEGER NOT NULL DEFAULT 0
        );
        CREATE TABLE IF NOT EXISTS capacity_overrides (
            id              INTEGER PRIMARY KEY AUTOINCREMENT,
            owner           TEXT    NOT NULL,
            date            TEXT    NOT NULL,         -- YYYY-MM-DD
            capacity        REAL    NOT NULL,          -- 0 ≤ capacity ≤ ownerCapacity[owner]
            modified_by     TEXT    NOT NULL DEFAULT '',
            modified_ts     TEXT    NOT NULL DEFAULT '',
            note            TEXT    NOT NULL DEFAULT '',
            UNIQUE(owner, date)
        );
        CREATE TABLE IF NOT EXISTS planning_sessions (
            id              TEXT PRIMARY KEY,
            name            TEXT NOT NULL,
            type            TEXT NOT NULL CHECK(type IN ('Review','Sprint','Release')),
            status          TEXT NOT NULL DEFAULT 'draft'
                                CHECK(status IN ('draft','committed','discarded')),
            created_by      TEXT NOT NULL,
            created_ts      TEXT NOT NULL,
            committed_ts    TEXT,
            release_number  TEXT,
            release_notes   TEXT,
            payload         TEXT NOT NULL DEFAULT '{}'
        );
        -- Stage 3b: per-user notification inbox (private; internal/in-app only)
        CREATE TABLE IF NOT EXISTS notifications (
            id          INTEGER PRIMARY KEY AUTOINCREMENT,
            username    TEXT NOT NULL,                 -- recipient
            type        TEXT NOT NULL,                 -- mention|watch_status|watch_comment|assigned
            item_id     INTEGER,
            item_name   TEXT,
            message     TEXT NOT NULL DEFAULT '',
            actor       TEXT,
            created_ts  TEXT NOT NULL,
            read        INTEGER NOT NULL DEFAULT 0
        );
        CREATE INDEX IF NOT EXISTS idx_notif_user ON notifications(username, read);
        -- Stage 3b: item watchers (kept OUT of the item JSON blob, which update_project
        -- fully replaces from the client body - a blob field would be wiped on next save)
        CREATE TABLE IF NOT EXISTS watchers (
            item_id     INTEGER NOT NULL,
            username    TEXT NOT NULL,
            PRIMARY KEY(item_id, username)
        );
        -- Stage 6: per-user "viewed" trail (feeds the beta My Home → Recent merge).
        -- One row per (user, item); the timestamp is upserted on each open.
        CREATE TABLE IF NOT EXISTS recent_views (
            username    TEXT NOT NULL,
            item_id     INTEGER NOT NULL,
            viewed_ts   TEXT NOT NULL,
            PRIMARY KEY(username, item_id)
        );
        CREATE INDEX IF NOT EXISTS idx_recent_user ON recent_views(username, viewed_ts);
        -- Team Calendar (Phase 1): non-ticket work (PTO/Training/On Call/...). The
        -- type_id references an `assignmentTypes` config entry (config-backed, like
        -- boards). Capacity impacts reduce the OWNER's effective capacity per day.
        CREATE TABLE IF NOT EXISTS assignments (
            id                 INTEGER PRIMARY KEY AUTOINCREMENT,
            type_id            TEXT    NOT NULL,             -- assignmentTypes[].id
            owner              TEXT    NOT NULL DEFAULT '',  -- capacity pool this counts against
            username           TEXT    NOT NULL DEFAULT '',  -- the person (users[].username)
            start_date         TEXT    NOT NULL,             -- YYYY-MM-DD
            end_date           TEXT    NOT NULL,             -- YYYY-MM-DD (inclusive)
            description         TEXT    NOT NULL DEFAULT '',
            recurrence         TEXT    NOT NULL DEFAULT 'none',
            notes              TEXT    NOT NULL DEFAULT '',
            recurrence_parent  INTEGER,
            created_by         TEXT    NOT NULL DEFAULT '',
            created_ts         TEXT    NOT NULL DEFAULT '',
            updated_ts         TEXT    NOT NULL DEFAULT ''
        );
        CREATE INDEX IF NOT EXISTS idx_assign_owner ON assignments(owner, start_date, end_date);
        CREATE INDEX IF NOT EXISTS idx_assign_user  ON assignments(username, start_date, end_date);
        """)
        # ── Live migrations: add new columns if they don't exist yet ─────────────
        for _col, _defn in [
            ("locked_by", "TEXT"),
            ("locked_ts", "TEXT"),
            ("snapshot",  "TEXT NOT NULL DEFAULT '{}'"),
        ]:
            try:
                c.execute(f"ALTER TABLE planning_sessions ADD COLUMN {_col} {_defn}")
            except Exception:
                pass  # column already exists - ignore
        # Migrate capacity_overrides: add note column
        try:
            c.execute("ALTER TABLE capacity_overrides ADD COLUMN note TEXT NOT NULL DEFAULT ''")
        except Exception:
            pass  # column already exists
        # Stage 4: single-level comment threads. parent_id NULL = top-level; a reply
        # carries its (root) parent's id. Existing comments stay top-level.
        try:
            c.execute("ALTER TABLE comments ADD COLUMN parent_id INTEGER")
        except Exception:
            pass  # column already exists
        # 1B: portal reporter replies (source='portal') - drives the public /ticket thread.
        try:
            c.execute("ALTER TABLE comments ADD COLUMN source TEXT")
        except Exception:
            pass  # column already exists
        # ── Phase 1 (JIRA-REPLACEMENT.md): indexed columns mirrored from item JSON ──
        for _col, _defn in [
            ("item_key", "TEXT"), ("type", "TEXT"), ("status", "TEXT"),
            ("parent_id", "INTEGER"), ("product", "TEXT"), ("owner", "TEXT"),
            ("assignee", "TEXT"), ("reporter", "TEXT"), ("priority", "TEXT"),
            ("rank", "TEXT"), ("story_points", "REAL"), ("sprint_id", "TEXT"),
            ("archived", "INTEGER NOT NULL DEFAULT 0"), ("updated_ts", "TEXT"),
        ]:
            try:
                c.execute(f"ALTER TABLE projects ADD COLUMN {_col} {_defn}")
            except Exception:
                pass  # column already exists
        for _idx, _expr in [
            ("idx_projects_parent",   "parent_id"), ("idx_projects_status",  "status"),
            ("idx_projects_product",  "product"),   ("idx_projects_owner",   "owner"),
            ("idx_projects_sprint",   "sprint_id"), ("idx_projects_archived","archived"),
        ]:
            c.execute(f"CREATE INDEX IF NOT EXISTS {_idx} ON projects({_expr})")
        # Partial unique index: keys are unique when present, many NULLs allowed.
        try:
            c.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_projects_key "
                      "ON projects(item_key) WHERE item_key IS NOT NULL")
        except Exception:
            pass
        _ensure_fts(c)   # FTS5 search index (no-op if fts5 module unavailable)
        defaults = {
            "developers":   [],
            "statuses":     ["In Progress","Planned","In Testing","Released","TBD","Backlogged"],
            "delayReasons": ["Testing delays","Partner Delays","Scope Creep",
                             "Priority Shift","Start Delayed","Board Testing",
                             "Resource Constraint","External Dependency",
                             "Requirements Change","Technical Blocker"],
            "changeReasons": ["Scope Change","Resource Constraint","Technical Blocker",
                              "External Dependency","Priority Shift",
                              "Revised Estimate","Partner Delays","Other"],
            "deferReasons":  ["Not Ready","Deprioritised","Waiting on External",
                              "Resource Unavailable","Other"],
            "departments":  [],
            "products":     [{"name":"Fraznet","builtin":True},
                             {"name":"HubSpot","builtin":True}],
            "users":        [{"username":"admin","password":_get_init_password(team),
                              "builtin":True,"role":"admin","mustChangePassword":True}],
            "types":        [{"name":"Feature","color":""},{"name":"Enhancement","color":""},{"name":"Maintenance","color":""}],
            # Per-type "Scheduled" flag (appears on Gantt + consumes capacity). Default
            # every type ON so behavior is unchanged until an admin unchecks one.
            "typeScheduled": {"Feature":True,"Enhancement":True,"Maintenance":True},
            # Status-flow anchor for the default set: drag-order is the rank; "Released" is
            # the terminal (done) status. No readiness-floor seed - the default set has no
            # "ready" gate; admins flag one in Admin → Statuses if wanted. Admin-editable.
            "statusIsTerminal": {"Released": True},
            # /beta rich-text editor (Tiptap) master switch. Default ON for the beta
            # surface; flipping to False reverts Description+Comments to the classic
            # lightweight editor with no redeploy. Classic root never reads this.
            "richTextEditor": True,
            # M1: which assignment type the Maintenance Duty rotation uses (empty = auto-detect
            # a type whose name matches "maintenance duty" case-insensitively). Admin-settable.
            "maintenanceDutyTypeId": "",
            # Public intake portal (/report): whether this team is exposed in the
            # external ticket-creation page, and which item Types it offers there.
            "intakeEnabled": False,
            "intakeProjects": [],  # which projects (products) are exposed; empty = all
            "intakeNotifyEmail": "",  # team inbox that gets a copy of each portal ticket
            "intakeTypes": [],     # empty = offer ALL of the team's types
            "intakeProjectEmails": {},  # optional per-project notify override {product: email}; falls back to intakeNotifyEmail
            "intakeDomains": [],   # allowed reporter email domains (empty = allow any)
            "departmentMeta": {},  # per-department {name: {color, emails}} - pill color + notify list
            # Team Calendar (Phase 1): assignment types (config-backed collection, like
            # boards - edited via /api/assignment-types, NOT the generic config route).
            "assignmentTypes": _DEFAULT_ASSIGNMENT_TYPES,
        }
        for k, v in defaults.items():
            c.execute("INSERT OR IGNORE INTO config(key,value) VALUES(?,?)",
                      (k, json.dumps(v)))
    _migrate_passwords(team)
    _migrate_config_keys(team)
    _migrate_avatar_colors(team)   # Stage 6a: every user gets an avatarColor
    _migrate_sprint_snapshots(team)  # Planning Stage 1: durable snapshot for completed sprints
    _migrate_maintenance_flag(team)  # M1.4: seed maintenance=True on the "Bug Fix" type (presence-only)
    # Backfill indexed columns in its OWN transaction (after the schema migration
    # has committed the new columns). Keeping it separate means a rollback in the
    # schema block - or a concurrent worker boot - can't lose the backfill. It is
    # self-limiting (only rows with updated_ts IS NULL) and idempotent.
    try:
        with db(team) as c:
            _unindexed = c.execute("SELECT id, data FROM projects WHERE updated_ts IS NULL").fetchall()
            for _r in _unindexed:
                try:
                    _reindex_project(c, _r["id"], json.loads(_r["data"]))
                except Exception:
                    pass
            # (Re)build the FTS index if it's out of sync (first create / drift).
            if _FTS_ENABLED:
                try:
                    fts_n  = c.execute("SELECT count(*) FROM projects_fts").fetchone()[0]
                    proj_n = c.execute("SELECT count(*) FROM projects").fetchone()[0]
                    if fts_n != proj_n:
                        c.execute("DELETE FROM projects_fts")
                        for _r in c.execute("SELECT id, data FROM projects").fetchall():
                            _fts_sync(c, _r["id"], json.loads(_r["data"]))
                        print(f"[Search] Built FTS index ({proj_n} items) for team '{team}'")
                except Exception as e:
                    log.warning(f"[Search] FTS backfill failed for '{team}': {e}")
        if _unindexed:
            print(f"[Migration] Indexed {len(_unindexed)} item(s) for team '{team}'")
    except Exception as e:
        log.warning(f"[Migration] index backfill failed for '{team}': {e}")
    _initialized_teams.add(team)
    print(f"[DB] Team '{team}' ready: {team_db_path(team)}")

_migrated_teams: set = set()

def _migrate_config_keys(team: str):
    """Backfill any new config keys that didn't exist when the team was created.

    Idempotent and cheap to call, but guarded so it runs at most once per team
    per process: boot() migrates all teams and init_team_db() migrates on
    creation, so the per-request call in GET /api/all was re-reading the whole
    config table (and potentially writing) on every page load for no benefit.
    """
    if team in _migrated_teams:
        return
    new_keys = {
        "changeReasons": ["Scope Change","Resource Constraint","Technical Blocker",
                          "External Dependency","Priority Shift",
                          "Revised Estimate","Partner Delays","Other"],
        "deferReasons":  ["Not Ready","Deprioritised","Waiting on External",
                          "Resource Unavailable","Other"],
        "departments":   [],
        "statusIsDefault":  {},
        "statusIsDeferred": {},
        "jiraSyncConfig":   {"enabled": False, "intervalMinutes": 30},
        "jiraEnabled":      True,
        "statusIsReleased": {},
        "statusIsApproved": {},
        "statusIsTesting":  {},
        "statusIsBlocked":  {},
        "richTextEditor":   True,
        "intakeEnabled":    False,
        "intakeProjects":   [],
        "intakeTypes":      [],
        "intakeNotifyEmail": "",
        "intakeProjectEmails": {},
        "intakeDomains": [],
        "departmentMeta": {},
        "assignmentTypes": _DEFAULT_ASSIGNMENT_TYPES,
        "maintenanceDutyTypeId": "",
    }
    # Keys where False/0/empty-string is a valid intentional value - only seed if key is MISSING,
    # never overwrite an existing value even if it's falsy. (assignmentTypes: presence-only so
    # an admin who deletes all types isn't re-seeded on next boot.)
    presence_only_keys = {"jiraEnabled", "jiraSyncConfig", "richTextEditor", "intakeEnabled", "intakeProjects", "intakeTypes", "intakeNotifyEmail", "intakeProjectEmails", "intakeDomains", "departmentMeta", "assignmentTypes", "maintenanceDutyTypeId"}

    with db(team) as c:
        existing = {r[0]: json.loads(r[1]) for r in c.execute("SELECT key,value FROM config").fetchall()}
        for k, v in new_keys.items():
            if k in presence_only_keys:
                # Only insert if the key doesn't exist at all - never overwrite
                if k not in existing:
                    c.execute(
                        "INSERT INTO config(key,value) VALUES(?,?) "
                        "ON CONFLICT(key) DO NOTHING",
                        (k, json.dumps(v))
                    )
                    print(f"[Migration] Seeded config key '{k}' for team '{team}'")
            else:
                # Insert if missing OR if row exists but value is empty/null
                if k not in existing or not existing[k]:
                    c.execute(
                        "INSERT INTO config(key,value) VALUES(?,?) "
                        "ON CONFLICT(key) DO UPDATE SET value=excluded.value",
                        (k, json.dumps(v))
                    )
                    print(f"[Migration] Seeded config key '{k}' for team '{team}'")
        # typeScheduled: per-type "appears on Gantt + consumes capacity" flag. Seed
        # to {every existing type: True} so behavior is unchanged until an admin
        # unchecks one. Seed only when MISSING - never overwrite admin choices.
        # (Types absent from the map still read as scheduled via isScheduledType,
        # so types added later default to scheduled too.)
        if "typeScheduled" not in existing:
            _types = existing.get("types") or []
            seeded = {}
            for _t in _types:
                _nm = _t.get("name") if isinstance(_t, dict) else _t
                if _nm:
                    seeded[_nm] = True
            c.execute(
                "INSERT INTO config(key,value) VALUES(?,?) ON CONFLICT(key) DO NOTHING",
                ("typeScheduled", json.dumps(seeded))
            )
            print(f"[Migration] Seeded config key 'typeScheduled' for team '{team}'")
        # Status-flow anchors: the /beta flow rank reads the drag-ordered `statuses`, but
        # terminal (done) + readiness-floor (Approved) come from these flags. Seed sensible
        # defaults ONLY when unset AND the matching default-named status exists - never
        # clobber a team that already configured (or uses custom names). Teams with custom
        # names set these via Admin → Statuses; the beta helper falls back meanwhile.
        _sts = existing.get("statuses") or []
        for _flag, _name in (("statusIsTerminal", "Released"), ("statusIsApproved", "Approved")):
            if _name in _sts and not existing.get(_flag):
                c.execute(
                    "INSERT INTO config(key,value) VALUES(?,?) "
                    "ON CONFLICT(key) DO UPDATE SET value=excluded.value",
                    (_flag, json.dumps({_name: True}))
                )
                print(f"[Migration] Seeded status-flow flag '{_flag}' for team '{team}'")
    _migrated_teams.add(team)

def _migrate_passwords(team: str):
    with db(team) as c:
        row = c.execute("SELECT value FROM config WHERE key='users'").fetchone()
        if not row: return
        users = json.loads(row["value"])
        changed = False
        for u in users:
            pw = u.get("password", "")
            if pw and not is_hashed(pw):
                u["password"] = hash_password(pw)
                changed = True
        if changed:
            c.execute("UPDATE config SET value=? WHERE key='users'", (json.dumps(users),))

# ── Per-user avatar colors (Stage 6a) ─────────────────────────────────────────
# 24 evenly-spaced hues at S58%/L44% - dark enough for white avatar text AND usable
# as pill text on a light tint. Deterministic; picker prefers a hue not already in use.
def _hsl_hex(h, s, l):
    c = (1 - abs(2*l - 1)) * s; x = c * (1 - abs((h/60.0) % 2 - 1)); m = l - c/2
    if   h < 60:  r, g, b = c, x, 0
    elif h < 120: r, g, b = x, c, 0
    elif h < 180: r, g, b = 0, c, x
    elif h < 240: r, g, b = 0, x, c
    elif h < 300: r, g, b = x, 0, c
    else:         r, g, b = c, 0, x
    return '#%02x%02x%02x' % (round((r+m)*255), round((g+m)*255), round((b+m)*255))
_AVATAR_PALETTE = [_hsl_hex(i * 360.0/24, 0.58, 0.44) for i in range(24)]

def _pick_avatar_color(used, seed=""):
    used_l = {str(c).lower() for c in used if c}
    for col in _AVATAR_PALETTE:
        if col.lower() not in used_l:
            return col
    return _AVATAR_PALETTE[int(hashlib.md5((seed or "x").encode()).hexdigest(), 16) % len(_AVATAR_PALETTE)]

def _migrate_avatar_colors(team: str):
    """Idempotent backfill: fill avatarColor for every user missing one, preferring an
    unused hue. Never overwrites a stored color (jr.frisby's #2f86de stays)."""
    with db(team) as c:
        row = c.execute("SELECT value FROM config WHERE key='users'").fetchone()
        if not row:
            return
        users = json.loads(row["value"])
        used = {u.get("avatarColor") for u in users if u.get("avatarColor")}
        changed = False
        for u in users:
            if not u.get("avatarColor"):
                col = _pick_avatar_color(used, u.get("username", ""))
                u["avatarColor"] = col; used.add(col); changed = True
        if changed:
            c.execute("UPDATE config SET value=? WHERE key='users'", (json.dumps(users),))

# ── Sprint snapshots (Planning Stage 1) ───────────────────────────────────────
# A completed sprint's Items/Points must be a durable snapshot, not re-derived from
# live membership (carried-over items have moved off, so a finished sprint reads 0/0).
# Going forward the client writes sp.snapshot at completion. This one-time, idempotent
# migration BACKFILLS a snapshot for existing Completed sprints by replaying the FULL
# activity log (not the 500-row client window). Reconstructed points are current (not
# historical) and the snapshot is flagged reconstructed=True. Never overwrites a snapshot.
_SP_DONE_RE   = re.compile(r"^Sprint planning: (.+?) completed → (moved to (.+)|returned to backlog)$")
_SP_REASSIGN_RE = re.compile(r"^Sprint planning: Sprint (.+) → (.+)$")
_SP_REMOVED_MSG = "Sprint planning: removed from sprint (returned to backlog)"

def _reconstruct_sprint_history(acts, by_name, name_of):
    """Port of the client _parseSprintActivities: replay an item's ordered
    'Sprint planning: …' messages into [{sprintId, addedAt, outcome}]. `acts` are
    dicts {message, created_ts} oldest-first; by_name maps sprint name→id, name_of id→name."""
    hist = []
    def name_to_id(n): return by_name.get(n, n)
    def sh_name(sid):  return name_of.get(sid, sid)
    def open_for(name):
        for k in range(len(hist) - 1, -1, -1):
            if sh_name(hist[k]["sprintId"]) == name and not hist[k]["outcome"]:
                return hist[k]
        return None
    for a in acts:
        m = a.get("message") or ""
        ts = (a.get("created_ts") or "")[:10]
        mc = _SP_DONE_RE.match(m)
        if mc:
            from_name, carried = mc.group(1), bool(mc.group(3))
            e = open_for(from_name)
            if e: e["outcome"] = "carried-over" if carried else "returned-to-backlog"
            else: hist.append({"sprintId": name_to_id(from_name), "addedAt": "",
                               "outcome": "carried-over" if carried else "returned-to-backlog"})
            if carried:
                hist.append({"sprintId": name_to_id(mc.group(3)), "addedAt": ts, "outcome": ""})
            continue
        if m == _SP_REMOVED_MSG:
            for k in range(len(hist) - 1, -1, -1):
                if not hist[k]["outcome"]:
                    hist[k]["outcome"] = "returned-to-backlog"; break
            continue
        ma = _SP_REASSIGN_RE.match(m)
        if ma:
            new_name = ma.group(2)
            for h in hist:
                if not h["outcome"] and sh_name(h["sprintId"]) != new_name:
                    h["outcome"] = "returned-to-backlog"
            if not open_for(new_name):
                hist.append({"sprintId": name_to_id(new_name), "addedAt": ts, "outcome": ""})
    return hist

def _migrate_maintenance_flag(team: str):
    """M1.4: one-time, presence-only seed of maintenance=True on a type named exactly
    "Bug Fix" (the M1.2 duty predicate, now config-driven). Only sets the flag when the
    key is ABSENT on that type object - never overwrites an admin's explicit choice."""
    with db(team) as c:
        row = c.execute("SELECT value FROM config WHERE key='types'").fetchone()
        if not row:
            return
        try:
            types = json.loads(row["value"]) or []
        except Exception:
            return
        changed = False
        for t in types:
            if isinstance(t, dict) and t.get("name") == "Bug Fix" and "maintenance" not in t:
                t["maintenance"] = True
                changed = True
        if changed:
            c.execute("UPDATE config SET value=? WHERE key='types'", (json.dumps(types),))
            print(f"[Migration] {team}: seeded maintenance=True on the 'Bug Fix' type")

def _migrate_sprint_snapshots(team: str):
    with db(team) as c:
        srow = c.execute("SELECT value FROM config WHERE key='sprints'").fetchone()
        if not srow:
            return
        try:
            sprints = json.loads(srow["value"]) or []
        except Exception:
            return
        pending = [s for s in sprints if isinstance(s, dict)
                   and s.get("state") == "Completed" and not s.get("snapshot")]
        if not pending:
            return
        items = {}
        for r in c.execute("SELECT id, data FROM projects").fetchall():
            try:
                p = json.loads(r["data"]); p["id"] = r["id"]; items[r["id"]] = p
            except Exception:
                continue
        acts_by_item = {}
        for r in c.execute("SELECT item_id, message, created_ts FROM activities "
                           "WHERE message LIKE 'Sprint planning:%' ORDER BY created_ts").fetchall():
            acts_by_item.setdefault(r["item_id"], []).append(
                {"message": r["message"], "created_ts": r["created_ts"] or ""})
        by_name = {(s.get("name") or ""): s.get("id") for s in sprints if isinstance(s, dict)}
        name_of = {s.get("id"): (s.get("name") or "") for s in sprints if isinstance(s, dict)}
        hist_by_item = {pid: _reconstruct_sprint_history(acts, by_name, name_of)
                        for pid, acts in acts_by_item.items()}

        def snap_item(pid, outcome):
            p = items.get(pid, {})
            return {"id": pid, "key": p.get("itemKey") or "", "name": p.get("name") or "",
                    "points": p.get("storyPoints"), "outcome": outcome or "completed"}

        for s in pending:
            sid = s.get("id"); rows = []; seen = set()
            # (1) reconstructed memberships that reference this sprint (carried / backlog)
            for pid, hist in hist_by_item.items():
                for h in hist:
                    if h.get("sprintId") == sid:
                        rows.append(snap_item(pid, h.get("outcome"))); seen.add(pid); break
            # (2) current members still tagged to this sprint (finished items that stayed)
            for pid, p in items.items():
                if pid not in seen and p.get("sprintId") == sid:
                    rows.append(snap_item(pid, "completed")); seen.add(pid)
            s["snapshot"] = {"takenAt": s.get("endDate") or "", "reconstructed": True, "items": rows}
        c.execute("UPDATE config SET value=? WHERE key='sprints'", (json.dumps(sprints),))
    print(f"[Migration] {team}: backfilled {len(pending)} sprint snapshot(s)")

# ── Boot: ensure 'development' team exists, migrate legacy DB if needed ────────
def boot():
    os.makedirs(TENANTS_DIR, exist_ok=True)
    dev_dir = os.path.join(TENANTS_DIR, "development")
    os.makedirs(dev_dir, exist_ok=True)

    # Migrate legacy roadmap.db → development team if new DB doesn't exist yet
    legacy_db = os.path.join(BASE, "roadmap.db")
    new_db    = team_db_path("development")
    if os.path.exists(legacy_db) and not os.path.exists(new_db):
        import shutil
        shutil.copy2(legacy_db, new_db)
        print(f"[Migration] Copied roadmap.db → {new_db}")

    # Also accept existing 'technology' team if it exists (backward compat)
    tech_db = team_db_path("technology")
    if os.path.exists(tech_db):
        tech_dir = os.path.join(TENANTS_DIR, "technology")
        os.makedirs(tech_dir, exist_ok=True)
        init_team_db("technology")

    init_team_db("development")

    # Run migration for ALL existing team DBs (catches teams created before new keys were added)
    import os as _os
    for _entry in _os.listdir(TENANTS_DIR):
        _tpath = _os.path.join(TENANTS_DIR, _entry)
        if _os.path.isdir(_tpath) and _os.path.exists(_os.path.join(_tpath, "roadmap.db")):
            init_team_db(_entry)          # ensure schema (adds new columns e.g. comments.source)
            _migrate_config_keys(_entry)
    # NOTE: item-key backfill runs in a separate pass (see _backfill_all_teams_keys
    # below) - boot() executes at import, too early to reference that helper here.

boot()

# ── Rate limiting ─────────────────────────────────────────────────────────────
_rate: dict = {}
_rate_last_prune: float = 0.0
RATE_WINDOW, RATE_MAX = 60, 10

def _check_rate_limit(ip: str):
    global _rate_last_prune
    now = time.time()
    # Prune stale IPs every 5 minutes
    if now - _rate_last_prune > 300:
        stale = [k for k, v in _rate.items() if not v or now - v[-1] > RATE_WINDOW]
        for k in stale:
            del _rate[k]
        _rate_last_prune = now
    attempts = [t for t in _rate.get(ip, []) if now - t < RATE_WINDOW]
    attempts.append(now)
    _rate[ip] = attempts
    if len(attempts) > RATE_MAX:
        raise HTTPException(429, f"Too many login attempts. Try again in {RATE_WINDOW} seconds.")

# ── Audit logging ─────────────────────────────────────────────────────────────
def write_audit(team: str, action: str, username: str = "", project_id=None,
                project_name: str = "", changes: dict = None):
    ts = datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M:%S UTC")
    with db(team) as c:
        c.execute(
            "INSERT INTO audit_log(ts,username,action,project_id,project_name,changes)"
            " VALUES(?,?,?,?,?,?)",
            (ts, username or "unknown", action,
             project_id, project_name, json.dumps(changes) if changes else None)
        )

def _audit_actor(requested, auth):
    """Resolve the attribution/actor for a mutation. A client may request ONLY the
    literal 'System' sentinel (used by automated ops like the client-side auto-release
    loop); any other value is ignored and the authenticated user is used - so an
    editor cannot attribute a change or comment to another real user."""
    return "System" if requested == "System" else auth.get("username", "")

