# ── Public intake portal (Tier 2): unauthenticated "Report an issue" ──────────
# A team opts in via the `intakeEnabled` config flag and picks which item Types
# are offered via `intakeTypes` (empty = all). These three endpoints are PUBLIC
# (no auth) and drive the server-rendered /report page. Writes are rate-limited,
# type-restricted, and land at the team's default status.
def _cfg_val(team: str, key: str, default):
    try:
        with db(team) as c:
            row = c.execute("SELECT value FROM config WHERE key=?", (key,)).fetchone()
        return json.loads(row["value"]) if row else default
    except Exception:
        return default

def _intake_open(team: str) -> bool:
    return bool(_cfg_val(team, "intakeEnabled", False))

def _intake_label(team: str) -> str:
    return team[:1].upper() + team[1:] if team else team

def _intake_types(team: str) -> list:
    allow = _cfg_val(team, "intakeTypes", []) or []
    names = [(t.get("name") if isinstance(t, dict) else t)
             for t in (_cfg_val(team, "types", []) or [])]
    names = [n for n in names if n]
    return [n for n in names if n in allow] if allow else names

def _intake_projects(team: str) -> list:
    """Exposed product/project names for a team (intakeProjects ∩ products; empty = all)."""
    sel = _cfg_val(team, "intakeProjects", []) or []
    prods = [(p.get("name") if isinstance(p, dict) else p)
             for p in (_cfg_val(team, "products", []) or [])]
    prods = [p for p in prods if p]
    return [p for p in prods if p in sel] if sel else prods

def _intake_notify_email(team: str, product: str = "") -> str:
    """Where a portal ticket's team-copy goes: the per-project override if one is
    set for this product, else the team-wide intakeNotifyEmail. Either value may be
    a comma/semicolon-separated list of addresses."""
    per = _cfg_val(team, "intakeProjectEmails", {}) or {}
    if isinstance(per, dict) and product:
        addr = (per.get(product) or "").strip()
        if addr:
            return addr
    return _cfg_val(team, "intakeNotifyEmail", "") or ""

def _intake_domain_ok(team: str, email: str) -> bool:
    """True if the reporter email is allowed to submit. When a team sets an
    `intakeDomains` allowlist, the email's domain must match one (case-insensitive,
    a leading '@' or '*.' is tolerated). Empty allowlist = allow any domain."""
    allow = _cfg_val(team, "intakeDomains", []) or []
    doms = [str(d).strip().lower().lstrip("@").lstrip("*.").lstrip(".")
            for d in allow if str(d).strip()]
    if not doms:
        return True
    dom = (email.rsplit("@", 1)[-1] if "@" in email else "").strip().lower()
    if not dom:
        return False
    # match the exact domain or any subdomain of an allowed domain
    return any(dom == d or dom.endswith("." + d) for d in doms)

def _intake_notify_usernames(team: str, item: dict, pid) -> set:
    """Flow users to bell-notify about a portal ticket: its watchers + the assignee
    + the owner. `assignee` is already a username; the `dev` owner is a developer
    label, resolved to Flow username(s) by a direct match or a user's ownerFilter.
    Best-effort - used for reporter replies (the team email path is separate)."""
    targets = set(_get_watchers(team, pid))
    if item.get("assignee"):
        targets.add(item["assignee"])
    owner = (item.get("dev") or "").strip()
    if owner:
        try:
            with db(team) as c:
                urow = c.execute("SELECT value FROM config WHERE key='users'").fetchone()
            for u in (json.loads(urow["value"]) if urow else []):
                uname = u.get("username")
                if uname and (uname == owner or u.get("ownerFilter") == owner):
                    targets.add(uname)
        except Exception:
            pass
    return targets

def _intake_departments(team: str) -> list:
    return [d for d in (_cfg_val(team, "departments", []) or []) if d]

